SELECT r.id AS reply_id, r.content, r.post_id, r.user_id, r.create_time, u.username, u.role AS user_role
FROM reply r
         JOIN user u ON r.user_id = u.id
WHERE r.post_id = #{postId}
ORDER BY r.create_time ASC
    LIMIT #{offset}, #{limit}

SELECT r.id AS reply_id, r.post_id, r.user_id, r.content, r.create_time, u.username, u.role AS user_role
FROM reply r
         JOIN user u ON r.user_id = u.id
WHERE r.user_id = #{userId}
ORDER BY r.create_time DESC
    LIMIT #{offset}, #{limit}
